// Script Continued Below
// RAJ 2020.02.18  STRY0063547 - Works with 2 UI Actions that Enable and Disable Shared Attachments for Stories STRY0060676 and STRY0063747
// if form action is either Enable Shared Attachments or Disable Shared Attachments, then prompt user before proceding.
function onSubmit() {
	var confirmationMessage = '';
	var standardAlert = true;
	var blnSubmitAction = false;
	var formAction = g_form.getActionName();
	switch(formAction){
		// RAJ STRY0063547
		// if form action is Disable Shared Attachments, then prompt user before proceding.
		case 'tasker_ProcTempDisableSharedAttachments':
			confirmationMessage = getMessage('Tasker - Template Shared Attachments Warning'); 
			break;
		// RAJ - 2020-03-27 - STRY0063747
		// if form action is Disable Shared Documents, then prompt user before proceding.
		case 'tasker_disableProcessSharedDocuments':
			confirmationMessage = getMessage('Tasker - Template Shared Documents Warning');
			break;
		case 'sysverb_delete':
			confirmationMessage = getMessage('Tasker - Template Delete Warning');
			break;
	}
	if(confirmationMessage == ''){
		// no confirmation requr
		blnSubmitAction = true;
	} else if (standardAlert) {
		blnSubmitAction = confirm(confirmationMessage);
	}
	return blnSubmitAction;	
}
